document.addEventListener("DOMContentLoaded", function () {
  if (window.innerWidth < 600) {
    const container = document.querySelector(".read-more-btn");
    const hiddenEls = document.querySelectorAll(".hide-text");

    if (!container || hiddenEls.length === 0) return;

    hiddenEls.forEach(el => el.style.display = "none");

    const wrapper = document.createElement("div");
    wrapper.className = "wp-block-button has-custom-width wp-block-button__width-100";
    wrapper.style.textAlign = "center";

    const btn = document.createElement("a");
    btn.className = "wp-block-button__link no-border-radius wp-element-button";
    btn.textContent = "Read More";
    btn.style.display = "inline-block";
    btn.style.width = "100%";
    btn.style.textAlign = "center";
    btn.style.marginBottom = "45px";

    wrapper.appendChild(btn);
    container.parentNode.insertBefore(wrapper, container.nextSibling);

    btn.addEventListener("click", function (e) {
      e.preventDefault();
      hiddenEls.forEach(el => el.style.display = "");
      wrapper.remove();
    });
  }
});
